pub const DeviceClass = struct {
    pub const DeviceClassData = union(enum) {
        key: struct {
            num_keys: u16,
            keys: []const u32,
        },
        button: struct {
            num_buttons: u16,
            state: []const u32,
            labels: []const xproto.Atom,
        },
        valuator: struct {
            number: u16,
            label: xproto.Atom,
            min: FP3232,
            max: FP3232,
            value: FP3232,
            resolution: u32,
