                    }
                },
                .button => |value| {
                    const required_pad = wire.requiredPad(writer.seek, 4, 2);
                    writer.splatByte(0, required_pad);
                    writer.writeInt(u16, value.num_buttons);
                    for (value.state) |elem| {
                        writer.writeInt(u32, elem);
                    }
                    for (value.labels) |elem| {
                        writer.writeInt(u32, @intFromEnum(elem));
                    }
                },
                .valuator => |value| {
                    const required_pad = wire.requiredPad(writer.seek, 4, 2);
                    writer.splatByte(0, required_pad);
                    writer.writeInt(u16, value.number);
                    writer.writeInt(u32, @intFromEnum(value.label));
                    value.min.encode(writer);
                    value.max.encode(writer);
                    value.value.encode(writer);
                    writer.writeInt(u32, value.resolution);
                    writer.writeByte(@intCast(@intFromEnum(value.mode)));
                    writer.splatByte(0, 3);
                },
                .scroll => |value| {
                    const required_pad = wire.requiredPad(writer.seek, 4, 2);
                    writer.splatByte(0, required_pad);
                    writer.writeInt(u16, value.number);
                    writer.writeInt(u16, @intCast(@intFromEnum(value.scroll_type)));
                    writer.splatByte(0, 2);
                    writer.writeInt(u32, value.flags);
                    value.increment.encode(writer);
                },
                .touch => |value| {
                    writer.writeByte(@intCast(@intFromEnum(value.mode)));
                    writer.writeByte(value.num_touches);
                },
                .gesture => |value| {
                    writer.writeByte(value.num_touches);
                    writer.splatByte(0, 1);
