                    const num_keys = try reader.takeInt(u16, .native);
                    const keys = try allocator.alloc(u32, @as(usize, num_keys));
                    errdefer allocator.free(keys);
                    var keys_decoded: usize = 0;
                    for (keys) |*elem| {
                        const elem_value = try reader.takeInt(u32, .native);
                        elem.* = elem_value;
                        keys_decoded += 1;
                    }
                    break :blk .{
                        .key = .{
                            .num_keys = num_keys,
                            .keys = keys,
                        },
                    };
                },
                DeviceClassType.Button => blk: {
                    const required_pad = wire.requiredPad(reader.seek, 4, 2);
                    if (required_pad != 0) _ = try reader.take(required_pad);
                    const num_buttons = try reader.takeInt(u16, .native);
                    const state = try allocator.alloc(u32, @as(usize, ((num_buttons + 31) / 32)));
                    errdefer allocator.free(state);
                    var state_decoded: usize = 0;
                    for (state) |*elem| {
