                        elem.* = elem_value;
                        state_decoded += 1;
                    }
                    const labels = try allocator.alloc(xproto.Atom, @as(usize, num_buttons));
                    errdefer allocator.free(labels);
                    var labels_decoded: usize = 0;
                    for (labels) |*elem| {
                        const elem_value = @as(xproto.Atom, @enumFromInt(try reader.takeInt(u32, .native)));
                        elem.* = elem_value;
                        labels_decoded += 1;
                    }
                    break :blk .{
                        .button = .{
                            .num_buttons = num_buttons,
                            .state = state,
                            .labels = labels,
                        },
                    };
                },
                DeviceClassType.Valuator => blk: {
                    const required_pad = wire.requiredPad(reader.seek, 4, 2);
                    if (required_pad != 0) _ = try reader.take(required_pad);
                    const number = try reader.takeInt(u16, .native);
                    const label = @as(xproto.Atom, @enumFromInt(try reader.takeInt(u32, .native)));
                    const min = try FP3232.decode(reader);
                    const max = try FP3232.decode(reader);
                    const value = try FP3232.decode(reader);
                    const resolution = try reader.takeInt(u32, .native);
                    const mode = @as(ValuatorMode, @enumFromInt(try reader.takeInt(u8, .native)));
                    _ = try reader.take(3);
                    break :blk .{
                        .valuator = .{
                            .number = number,
