                            .max = max,
                            .value = value,
                            .resolution = resolution,
                            .mode = mode,
                        },
                    };
                },
                DeviceClassType.Scroll => blk: {
                    const required_pad = wire.requiredPad(reader.seek, 4, 2);
                    if (required_pad != 0) _ = try reader.take(required_pad);
                    const number = try reader.takeInt(u16, .native);
                    const scroll_type = @as(ScrollType, @enumFromInt(try reader.takeInt(u16, .native)));
                    _ = try reader.take(2);
                    const flags = try reader.takeInt(u32, .native);
                    const increment = try FP3232.decode(reader);
                    break :blk .{
                        .scroll = .{
                            .number = number,
                            .scroll_type = scroll_type,
                            .flags = flags,
                            .increment = increment,
                        },
                    };
                },
                DeviceClassType.Touch => blk: {
                    const mode = @as(TouchMode, @enumFromInt(try reader.takeInt(u8, .native)));
                    const num_touches = try reader.takeByte();
                    break :blk .{
                        .touch = .{
                            .mode = mode,
                            .num_touches = num_touches,
                        },
                    };
                },
                DeviceClassType.Gesture => blk: {
                    const num_touches = try reader.takeByte();
                    _ = try reader.take(1);
                    break :blk .{
                        .gesture = .{
                            .num_touches = num_touches,
                        },
                    };
                },
            else => std.debug.panic("unsupported switch discriminator", .{}),
            };
        }

