            switch (self.*) {
                .key => |*value| {
                    allocator.free(value.keys);
                },
                .button => |*value| {
                    allocator.free(value.state);
                    allocator.free(value.labels);
                },
                .valuator => {
                },
                .scroll => {
                },
                .touch => {
                },
                .gesture => {
                },
            }
        }
    };

    type: DeviceClassType,
    len: u16,
    sourceid: u16,
    data: DeviceClassData,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeInt(u16, @intCast(@intFromEnum(self.type)));
