pub const XIDeviceInfo = struct {
    deviceid: u16,
    type: DeviceType,
    attachment: u16,
    enabled: bool,
    name: []const u8,
    classes: []DeviceClass,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeInt(u16, self.deviceid);
        writer.writeInt(u16, @intCast(@intFromEnum(self.type)));
        writer.writeInt(u16, self.attachment);
        writer.writeInt(u16, @intCast(self.classes.len));
        writer.writeInt(u16, @intCast(self.name.len));
        writer.writeByte(@intFromBool(self.enabled));
        writer.splatByte(0, 1);
        writer.write(self.name);
        writer.splatByte(0, wire.pad4(self.name.len));
