            elem.encode(writer);
        }
    }

    pub fn decode(allocator: std.mem.Allocator, reader: *std.Io.Reader) AllocDecodeError!@This() {
        const deviceid = try reader.takeInt(u16, .native);
        const @"type" = @as(DeviceType, @enumFromInt(try reader.takeInt(u16, .native)));
        const attachment = try reader.takeInt(u16, .native);
        const num_classes = try reader.takeInt(u16, .native);
        const name_len = try reader.takeInt(u16, .native);
        const enabled = (try reader.takeByte()) != 0;
        _ = try reader.take(1);
        const name_byte_len = @as(usize, name_len);
