        _ = try reader.take(wire.pad4(name.len));
        const classes = try allocator.alloc(DeviceClass, @as(usize, num_classes));
        errdefer allocator.free(classes);
        var classes_decoded: usize = 0;
        errdefer for (classes[0..classes_decoded]) |*elem| elem.deinit(allocator);
        for (classes) |*elem| {
            const elem_value = try DeviceClass.decode(allocator, reader);
            elem.* = elem_value;
            classes_decoded += 1;
        }
        return .{
            .deviceid = deviceid,
            .type = @"type",
            .attachment = attachment,
            .enabled = enabled,
            .name = name,
            .classes = classes,
        };
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.name);
        for (self.classes) |*elem| elem.deinit(allocator);
        allocator.free(self.classes);
