pub const ChangeDevicePropertyItems = union(enum) {
    @"8Bits": struct {
        data8: []const u8,
    },
    @"16Bits": struct {
        data16: []const u16,
    },
    @"32Bits": struct {
        data32: []const u32,
    },

    pub fn encode(self: @This(), writer: anytype) void {
        switch (self) {
            .@"8Bits" => |value| {
                writer.write(value.data8);
                writer.splatByte(0, wire.pad4(value.data8.len));
            },
            .@"16Bits" => |value| {
                for (value.data16) |elem| {
                    writer.writeInt(u16, elem);
                }
                writer.splatByte(0, wire.pad4(value.data16.len * 2));
            },
            .@"32Bits" => |value| {
                for (value.data32) |elem| {
                    writer.writeInt(u32, elem);
                }
            },
        }
    }

    pub fn decode(allocator: std.mem.Allocator, discriminator: anytype, num_items: anytype, reader: *std.Io.Reader) AllocDecodeError!@This() {
        return switch (discriminator) {
            PropertyFormat.@"8Bits" => blk: {
                const data8_byte_len = @as(usize, num_items);
                const data8_temp = try reader.take(data8_byte_len);
                const data8 = try allocator.dupe(u8, data8_temp);
                _ = try reader.take(wire.pad4(data8.len));
                break :blk .{
                    .@"8Bits" = .{
                        .data8 = data8,
                    },
                };
            },
            PropertyFormat.@"16Bits" => blk: {
                const data16 = try allocator.alloc(u16, @as(usize, num_items));
                errdefer allocator.free(data16);
                var data16_decoded: usize = 0;
                for (data16) |*elem| {
                    const elem_value = try reader.takeInt(u16, .native);
                    elem.* = elem_value;
                    data16_decoded += 1;
                }
                _ = try reader.take(wire.pad4(data16.len * 2));
                break :blk .{
                    .@"16Bits" = .{
                        .data16 = data16,
                    },
                };
            },
            PropertyFormat.@"32Bits" => blk: {
                const data32 = try allocator.alloc(u32, @as(usize, num_items));
                errdefer allocator.free(data32);
                var data32_decoded: usize = 0;
                for (data32) |*elem| {
                    const elem_value = try reader.takeInt(u32, .native);
                    elem.* = elem_value;
                    data32_decoded += 1;
                }
                break :blk .{
                    .@"32Bits" = .{
                        .data32 = data32,
                    },
                };
            },
        else => std.debug.panic("unsupported switch discriminator", .{}),
        };
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        switch (self.*) {
            .@"8Bits" => |*value| {
                allocator.free(value.data8);
            },
            .@"16Bits" => |*value| {
                allocator.free(value.data16);
            },
            .@"32Bits" => |*value| {
                allocator.free(value.data32);
            },
        }
    }
};

