pub fn decodeEvent(reader: *std.Io.Reader) DecodeError!global_events.Event {
    const code = (try reader.peek(1))[0] & 0x7f;
    return switch (code) {
        0 => .{ .XInputDeviceValuator = try DeviceValuatorEvent.decode(reader) },
        1 => .{ .XInputDeviceKeyPress = try DeviceKeyPressEvent.decode(reader) },
        2 => .{ .XInputDeviceKeyRelease = try DeviceKeyReleaseEvent.decode(reader) },
        3 => .{ .XInputDeviceButtonPress = try DeviceButtonPressEvent.decode(reader) },
        4 => .{ .XInputDeviceButtonRelease = try DeviceButtonReleaseEvent.decode(reader) },
        5 => .{ .XInputDeviceMotionNotify = try DeviceMotionNotifyEvent.decode(reader) },
        6 => .{ .XInputDeviceFocusIn = try DeviceFocusInEvent.decode(reader) },
        7 => .{ .XInputDeviceFocusOut = try DeviceFocusOutEvent.decode(reader) },
        8 => .{ .XInputProximityIn = try ProximityInEvent.decode(reader) },
        9 => .{ .XInputProximityOut = try ProximityOutEvent.decode(reader) },
        10 => .{ .XInputDeviceStateNotify = try DeviceStateNotifyEvent.decode(reader) },
        11 => .{ .XInputDeviceMappingNotify = try DeviceMappingNotifyEvent.decode(reader) },
        12 => .{ .XInputChangeDeviceNotify = try ChangeDeviceNotifyEvent.decode(reader) },
        13 => .{ .XInputDeviceKeyStateNotify = try DeviceKeyStateNotifyEvent.decode(reader) },
        14 => .{ .XInputDeviceButtonStateNotify = try DeviceButtonStateNotifyEvent.decode(reader) },
        15 => .{ .XInputDevicePresenceNotify = try DevicePresenceNotifyEvent.decode(reader) },
        16 => .{ .XInputDevicePropertyNotify = try DevicePropertyNotifyEvent.decode(reader) },
        else => blk: {
            const packet = try reader.take(32);
            var raw: [32]u8 = undefined;
            @memcpy(raw[0..], packet);
            break :blk .{ .Unknown = .{
                .code = packet[0] & 0x7f,
                .sequence = std.mem.readInt(u16, packet[2..4], .native),
                .raw = raw,
            } };
        },
    };
}

pub fn decodeXgeEvent(reader: *std.Io.Reader) DecodeError!global_events.Event {
    const header = try reader.peek(10);
    const event_type = std.mem.readInt(u16, header[8..10], .native);
    return switch (event_type) {
        1 => .{ .XInputDeviceChanged = try DeviceChangedEvent.decode(reader) },
        2 => .{ .XInputKeyPress = try KeyPressEvent.decode(reader) },
        3 => .{ .XInputKeyRelease = try KeyReleaseEvent.decode(reader) },
        4 => .{ .XInputButtonPress = try ButtonPressEvent.decode(reader) },
        5 => .{ .XInputButtonRelease = try ButtonReleaseEvent.decode(reader) },
        6 => .{ .XInputMotion = try MotionEvent.decode(reader) },
        7 => .{ .XInputEnter = try EnterEvent.decode(reader) },
        8 => .{ .XInputLeave = try LeaveEvent.decode(reader) },
        9 => .{ .XInputFocusIn = try FocusInEvent.decode(reader) },
        10 => .{ .XInputFocusOut = try FocusOutEvent.decode(reader) },
        11 => .{ .XInputHierarchy = try HierarchyEvent.decode(reader) },
        12 => .{ .XInputProperty = try PropertyEvent.decode(reader) },
        13 => .{ .XInputRawKeyPress = try RawKeyPressEvent.decode(reader) },
        14 => .{ .XInputRawKeyRelease = try RawKeyReleaseEvent.decode(reader) },
        15 => .{ .XInputRawButtonPress = try RawButtonPressEvent.decode(reader) },
        16 => .{ .XInputRawButtonRelease = try RawButtonReleaseEvent.decode(reader) },
        17 => .{ .XInputRawMotion = try RawMotionEvent.decode(reader) },
        18 => .{ .XInputTouchBegin = try TouchBeginEvent.decode(reader) },
        19 => .{ .XInputTouchUpdate = try TouchUpdateEvent.decode(reader) },
        20 => .{ .XInputTouchEnd = try TouchEndEvent.decode(reader) },
        21 => .{ .XInputTouchOwnership = try TouchOwnershipEvent.decode(reader) },
        22 => .{ .XInputRawTouchBegin = try RawTouchBeginEvent.decode(reader) },
        23 => .{ .XInputRawTouchUpdate = try RawTouchUpdateEvent.decode(reader) },
        24 => .{ .XInputRawTouchEnd = try RawTouchEndEvent.decode(reader) },
        25 => .{ .XInputBarrierHit = try BarrierHitEvent.decode(reader) },
        26 => .{ .XInputBarrierLeave = try BarrierLeaveEvent.decode(reader) },
        27 => .{ .XInputGesturePinchBegin = try GesturePinchBeginEvent.decode(reader) },
        28 => .{ .XInputGesturePinchUpdate = try GesturePinchUpdateEvent.decode(reader) },
        29 => .{ .XInputGesturePinchEnd = try GesturePinchEndEvent.decode(reader) },
        30 => .{ .XInputGestureSwipeBegin = try GestureSwipeBeginEvent.decode(reader) },
        31 => .{ .XInputGestureSwipeUpdate = try GestureSwipeUpdateEvent.decode(reader) },
        32 => .{ .XInputGestureSwipeEnd = try GestureSwipeEndEvent.decode(reader) },
        else => .{ .GEUnknown = try xproto.GeGenericEvent.decode(reader) },
    };
}

